mapper.select:
SELECT FROM recruit r LEFT JOIN member m ON r.writer_no = m.member_no WHERE 1 = 1
AND r.department = #{department}
ORDER BY CASE WHEN r.status = '모집중' AND (r.start_date IS NULL OR r.start_date <= CURDATE()) AND (r.end_date IS NULL OR r.end_date >= CURDATE()) THEN 0 WHEN r.status = '모집중' AND r.start_date > CURDATE() THEN 1 ELSE 2 END, r.recruit_no DESC LIMIT #{offset}, #{limit}

